var e=[{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`아아…… 아아아아아악!!`,JPN:`ああ……ああああああ！！`,ENG:`Ah... AAAAAHHHHH!!!`,TWN:`啊啊……！啊啊啊啊啊啊！！`},stage:{bg:`TRAIL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`내려 줘! 여기서 풀어 줘……!`,JPN:`下ろして！　放してよ……！`,ENG:`Let me down! Let me out of here...!`,TWN:`放我下去！快放開我……！`},stage:{bg:`TRAIL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`몸이, 몸이 너무 아파! 아각, 아가아아아악!`,JPN:`体が、体が痛いよ！　がはっ、ああああああっ！`,ENG:`My, my body, it hurts so much! Gah, AAAAGHHH!`,TWN:`好痛，身體好痛！啊啊，啊啊啊啊！`},stage:{bg:`TRAIL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`사람들이 전부 하늘로 떠오르잖아……?`,JPN:`人がみんな宙に浮いてる……？`,ENG:`The people are all being pulled up to the sky…?`,TWN:`人怎麼都浮在空中……？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`이게 어떻게 된 거예요, 에클레시아?`,JPN:`これはいったいどういうことですか、エクレシア？`,ENG:`What is going on here, Ecclesia?`,TWN:`這到底是怎麼回事，艾可露西亞？`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`타기리온의 권능이다.`,JPN:`タギリオンの権能だ。`,ENG:`It is the power of Thagirion.`,TWN:`是塔基里翁的能力。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`서둘러야겠구나. 과거의 경험이라 한들 너무 오래 머물면 너 역시 영향을 받을 터.`,JPN:`急がねばならぬ。過去の経験とはいえ、長居すればそなたもまた影響を受けよう。`,ENG:`We must hurry. Though this may be a past experience, it will affect you the longer you stay.`,TWN:`動作要快，在這過去的記憶中待太久的話，你也會受到影響。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`타기리온에게 말인가요?`,JPN:`タギリオンにですか？`,ENG:`Affected by Thagirion?`,TWN:`受到塔基里翁的影響？`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`얼마나 위험하길래 그래요? 국가적인 위협이라면─`,JPN:`そんなに危険なんですか？　国家的な脅威なら──`,ENG:`How dangerous is that? If it's close to a national threat–`,TWN:`到底有多危險？竟然說是國家級的威脅……`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`……30초.`,JPN:`……30秒。`,ENG:`...30 seconds.`,TWN:`……30秒。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`네?`,JPN:`え？`,ENG:`Excuse me?`,TWN:`什麼？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`30초 뒤면, 성흔을 얻지 못한 이 세계의 모든 지성체가 전멸한다.`,JPN:`30秒後には、聖痕を得られなかったこの世界のすべての知性体が全滅する。`,ENG:`In 30 seconds, all those without the Stigmata will be wiped from this world.`,TWN:`30秒後，這世上沒得到聖痕的所有智慧生命都將會消逝。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`30초라니요? 여기가 초고심도 이면세계라도 된단 말이에요?`,JPN:`30秒？　ここが超高深度の裏世界にでもなったっていうんですか？`,ENG:`30 seconds? Do you mean this world is going to become the hyperdepths of Counterside?`,TWN:`30秒？難道這裡會變成超深度異界？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`사람들이…… 변하고 있어? 급성 침식 증후군인가?`,JPN:`人々が……変化してる？　急性の侵食症候群なの？`,ENG:`Those people... are starting to mutate? Is this an acute Corruption Syndrome?`,TWN:`大家……正在發生異變？是急性侵蝕症候群？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`아냐…. 저건 마치…….`,JPN:`違う……あれはまるで……`,ENG:`No... This is as if...`,TWN:`不對……這簡直就像是……`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`골격이, 종 자체가 뒤틀리는 듯한…….`,JPN:`骨格が、生物としての種類も変えられているような……`,ENG:`Their skeleton, their species itself is twisting...`,TWN:`不只是骨骼，感覺是完全變成另一個種類……`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};